"use client";

import { getPlantComponent } from "./plant-graphics";

export type GrowthStage = 0 | 1 | 2 | 3 | 4;

interface PixelPlantProps {
  stage: GrowthStage;
  hobbyName: string;
  isWatered?: boolean;
  className?: string;
}

export function PixelPlant({
  stage,
  hobbyName,
  isWatered,
  className,
}: PixelPlantProps) {
  const Plant = getPlantComponent(hobbyName);

  return (
    <Plant
      stage={stage}
      isWatered={isWatered}
      className={className}
    />
  );
}

export function levelToPixelStage(level: string): GrowthStage {
  switch (level) {
    case "Seed": return 1;
    case "Sprout": return 2;
    case "Plant": return 3;
    case "Tree": return 4;
    default: return 1;
  }
}