"use client";

import { motion } from "framer-motion";

export type GrowthStage = 0 | 1 | 2 | 3 | 4;

interface PlantProps {
  stage: GrowthStage;
  isWatered?: boolean;
  className?: string;
}

const OUTLINE = "#1b1b1b";

// ---------- 🌵 FITNESS (CACTUS) ----------
export function FitnessPlant({ stage, className }: PlantProps) {
  return (
    <motion.svg viewBox="0 0 64 80" className={className}>
      <ellipse cx="32" cy="72" rx="12" ry="4" fill="rgba(0,0,0,0.25)" />

      <motion.g
        animate={{ scale: [1, 1.02, 1] }}
        transition={{ duration: 4, repeat: Infinity }}
        style={{ transformOrigin: "bottom center" }}
      >
        {stage >= 1 && (
          <>
            <rect x={27} y={40} width={10} height={28} fill={OUTLINE} />
            <rect x={28} y={42} width={8} height={24} fill="#2e7d32" />
            <rect x={30} y={42} width={2} height={24} fill="#66bb6a" />
          </>
        )}

        {stage >= 2 && (
          <>
            <rect x={20} y={48} width={8} height={4} fill="#2e7d32" />
            <rect x={36} y={52} width={8} height={4} fill="#2e7d32" />
          </>
        )}

        {stage >= 4 && (
          <rect x={30} y={36} width={4} height={4} fill="#ff6b6b" />
        )}
      </motion.g>
    </motion.svg>
  );
}

// ---------- 🌻 PHOTOGRAPHY ----------
export function PhotographyPlant({ stage, className }: PlantProps) {
  return (
    <motion.svg viewBox="0 0 64 80" className={className}>
      <ellipse cx="32" cy="72" rx="12" ry="4" fill="rgba(0,0,0,0.25)" />

      {stage >= 1 && (
        <rect x={30} y={40} width={4} height={24} fill="#2e7d32" />
      )}

      {stage >= 3 && (
        <>
          {[0, 60, 120, 180, 240, 300].map((r) => (
            <rect
              key={r}
              x={30}
              y={28}
              width={4}
              height={10}
              fill="#ffc107"
              transform={`rotate(${r} 32 32)`}
            />
          ))}
          <rect x={28} y={28} width={8} height={8} fill="#5d4037" />
        </>
      )}
    </motion.svg>
  );
}

// ---------- 🎨 ART (FLOWER) ----------
export function PaintingPlant({ stage, className }: PlantProps) {
  return (
    <motion.svg viewBox="0 0 64 80" className={className}>
      <ellipse cx="32" cy="72" rx="12" ry="4" fill="rgba(0,0,0,0.25)" />

      {stage >= 1 && (
        <rect x={30} y={40} width={4} height={24} fill="#388e3c" />
      )}

      {stage >= 3 && (
        <>
          {["#ff6b6b", "#4ecdc4", "#ffe66d", "#95e1d3"].map((c, i) => (
            <rect
              key={i}
              x={30}
              y={28}
              width={6}
              height={6}
              fill={c}
              transform={`rotate(${i * 90} 32 32)`}
            />
          ))}
        </>
      )}
    </motion.svg>
  );
}

// ---------- 📚 READING ----------
export function ReadingPlant({ stage, className }: PlantProps) {
  return (
    <motion.svg viewBox="0 0 64 80" className={className}>
      <ellipse cx="32" cy="72" rx="12" ry="4" fill="rgba(0,0,0,0.25)" />

      {stage >= 2 && (
        <>
          <rect x={24} y={40} width={16} height={12} fill="#8d6e63" />
          <rect x={24} y={40} width={8} height={12} fill="#6d4c41" />
        </>
      )}
    </motion.svg>
  );
}

// ---------- 🍳 COOKING ----------
export function CookingPlant({ stage, className }: PlantProps) {
  return (
    <motion.svg viewBox="0 0 64 80" className={className}>
      <ellipse cx="32" cy="72" rx="12" ry="4" fill="rgba(0,0,0,0.25)" />

      {stage >= 2 && (
        <>
          <rect x={28} y={50} width={4} height={14} fill="#558b2f" />
          <rect x={34} y={48} width={4} height={16} fill="#7cb342" />
        </>
      )}
    </motion.svg>
  );
}

// ---------- ✍ WRITING ----------
export function WritingPlant({ stage, className }: PlantProps) {
  return (
    <motion.svg viewBox="0 0 64 80" className={className}>
      <ellipse cx="32" cy="72" rx="12" ry="4" fill="rgba(0,0,0,0.25)" />

      {stage >= 2 && (
        <>
          <rect x={30} y={40} width={4} height={20} fill="#2e7d32" />
          <rect x={28} y={20} width={8} height={20} fill="#7986cb" />
        </>
      )}
    </motion.svg>
  );
}

// ---------- 🎵 MUSIC ----------
export function GuitarPlant({ stage, className }: PlantProps) {
  return (
    <motion.svg viewBox="0 0 64 80" className={className}>
      <ellipse cx="32" cy="72" rx="12" ry="4" fill="rgba(0,0,0,0.25)" />

      {stage >= 2 && (
        <>
          <rect x={30} y={40} width={4} height={20} fill="#8b5a2b" />
          <circle cx="32" cy="30" r="6" fill="#ffd700" />
        </>
      )}
    </motion.svg>
  );
}

// ---------- DEFAULT ----------
export function DefaultPlant({ stage, className }: PlantProps) {
  return (
    <motion.svg viewBox="0 0 64 80" className={className}>
      <ellipse cx="32" cy="72" rx="12" ry="4" fill="rgba(0,0,0,0.25)" />

      {stage >= 2 && (
        <>
          <rect x={30} y={40} width={4} height={20} fill="#2e7d32" />
          <rect x={24} y={30} width={16} height={10} fill="#4caf50" />
        </>
      )}
    </motion.svg>
  );
}

// ---------- SELECTOR ----------
export function getPlantComponent(name: string) {
  const n = name.toLowerCase();

  if (n.includes("fitness") || n.includes("gym")) return FitnessPlant;
  if (n.includes("photo")) return PhotographyPlant;
  if (n.includes("paint") || n.includes("art")) return PaintingPlant;
  if (n.includes("read") || n.includes("book")) return ReadingPlant;
  if (n.includes("cook")) return CookingPlant;
  if (n.includes("write")) return WritingPlant;
  if (n.includes("music") || n.includes("guitar")) return GuitarPlant;

  return DefaultPlant;
}